  4→export default function Newsletter() {
  5→  const [formValue, setFormValue] = useState({ email: "" });
  6→  const [formError, setFormError] = useState({});
  7→  const [submit, setSubmit] = useState(false);
  8→  const [loading, setLoading] = useState(false);
  9→
 10→  const ResetLocation = () => window.scrollTo(0, 0);
 11→
 12→  const handleSubmit = async (e) => {
 13→    e.preventDefault();
 14→    setLoading(true);
 15→    setFormError(validateForm(formValue));
 16→    if (Object.keys(validateForm(formValue)).length > 0) {
 17→      setLoading(false);
 18→      return null;
 19→    } else {
 20→      setSubmit(true);
 21→      setFormValue({ email: "" });
 22→      setLoading(false);
 23→    }
 24→  };
 25→  const handleValidation = (e) => {
 26→    const { name, value } = e.target;
 27→    setFormValue({ ...formValue, [name]: value });
 28→  };
 29→
 30→  const validateForm = (value) => {
 31→    const errors = {};
 32→    const emailValidation = /^\w+([.-]?\w+)*@\w+([.-]?\w+)*(\.\w{2,3})+$/;
 33→    if (!value.email) {
 34→      errors.email = "Empty email field";
 35→    } else if (!emailValidation.test(value.email)) {
 36→      errors.email = "Invalid email format";
 37→    }
 38→    return errors;
 39→  };
 40→  return (
 41→    <article className="bg-gray-900">
 42→      <section className="max-w-7xl mx-auto py-12 px-4 sm:px-6 lg:py-16 lg:px-8 lg:flex lg:items-center">
