 45→            className="text-3xl font-extrabold tracking-tight text-white sm:text-4xl"
 46→            id="newsletter-headline">
 47→            Sign up for our newsletter
 48→          </h2>
 49→          <p className="mt-3 max-w-3xl text-lg leading-6 text-gray-300">
