 57→          {loading ? (
 58→            <React.Fragment>
 59→              <div role="status">
 60→                <svg
 61→                  aria-hidden="true"
 62→                  className="w-10 h-10 mt-6 text-gray-200 animate-spin dark:text-gray-600 fill-indigo-400"
 63→                  viewBox="0 0 100 101"
 64→                  fill="none"
 65→                  xmlns="http://www.w3.org/2000/svg">
 66→                  <path
 67→                    d="M100 50.5908C100 78.2051 77.6142 100.591 50 100.591C22.3858 100.591 0 78.2051 0 50.5908C0 22.9766 22.3858 0.59082 50 0.59082C77.6142 0.59082 100 22.9766 100 50.5908ZM9.08144 50.5908C9.08144 73.1895 27.4013 91.5094 50 91.5094C72.5987 91.5094 90.9186 73.1895 90.9186 50.5908C90.9186 27.9921 72.5987 9.67226 50 9.67226C27.4013 9.67226 9.08144 27.9921 9.08144 50.5908Z"
 68→                    fill="currentColor"
 69→                  />
 70→                  <path
 71→                    d="M93.9676 39.0409C96.393 38.4038 97.8624 35.9116 97.0079 33.5539C95.2932 28.8227 92.871 24.3692 89.8167 20.348C85.8452 15.1192 80.8826 10.7238 75.2124 7.41289C69.5422 4.10194 63.2754 1.94025 56.7698 1.05124C51.7666 0.367541 46.6976 0.446843 41.7345 1.27873C39.2613 1.69328 37.813 4.19778 38.4501 6.62326C39.0873 9.04874 41.5694 10.4717 44.0505 10.1071C47.8511 9.54855 51.7191 9.52689 55.5402 10.0491C60.8642 10.7766 65.9928 12.5457 70.6331 15.2552C75.2735 17.9648 79.3347 21.5619 82.5849 25.841C84.9175 28.9121 86.7997 32.2913 88.1811 35.8758C89.083 38.2158 91.5421 39.6781 93.9676 39.0409Z"
 72→                    fill="currentFill"
 73→                  />
 74→                </svg>
 75→                <span className="sr-only">Loading...</span>
 76→              </div>
 77→            </React.Fragment>
 78→          ) : submit && Object.keys(formError).length === 0 ? (
 79→            <p className="font-medium text-green-600 sm:text-xl lg:text-lg xl:text-xl">
 80→              Hold tight! Our representative will contact you shortly via email
 81→            </p>
 82→          ) : (
 83→            <form onSubmit={handleSubmit} className="sm:flex">
 84→              <label htmlFor="email" className="sr-only">
 85→                Email address
 86→              </label>
 87→              <input
 88→                id="email"
 89→                name="email"
 90→                type="text"
 91→                onChange={handleValidation}
 92→                className="w-full px-5 py-3 border-2 border-indigo-600 text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-300 focus:ring-offset-gray-900 sm:max-w-xs rounded-md"
 93→                placeholder="Enter your email"
 94→              />
 95→
 96→              <section className="mt-3 rounded-md shadow sm:mt-0 sm:ml-3 sm:flex-shrink-0">
 97→                <button
 98→                  type="submit"
 99→                  className="w-full flex items-center justify-center px-5 py-3 border border-transparent text-base font-medium rounded-md text-white bg-indigo-500 hover:bg-indigo-600 focus:outline-none  focus:ring-offset-gray-800 focus:ring-indigo-500">
100→                  Notify me
101→                </button>
102→              </section>
103→              <span className="text-red-400 absolute sm:mt-14 md:mt-16">
104→                {formError.email}
105→              </span>
106→            </form>
107→          )}
108→          <p className="text-sm text-gray-300 mt-11">
109→            We care about the protection of your data. Read our{" "}
110→            <Link
111→              onClick={ResetLocation}
112→              to="/privacy"
113→              className="text-white font-medium underline">
114→              Privacy Policy.
115→            </Link>
116→          </p>
117→        </section>
118→      </section>
119→    </article>
120→  );
121→}
