  1→import { useState } from "react";
  2→import { useNavigate } from "react-router-dom";
  3→
  4→const Profile = ({
  5→  user,
  6→  updateUser,
  7→  deleteUser,
  8→  setLoggedIn,
  9→  setTriggeredLogout,
 10→}) => {
 11→  const navigator = useNavigate();
 12→  const [formValue, setFormValue] = useState({});
 13→  const [formErrors, setFormErrors] = useState({});
 14→  const [deleteRequest, setDeleteRequest] = useState(false);
 15→  const [editFullName, setEditFullName] = useState(false);
 16→  const [editEmail, setEditEmail] = useState(false);
 17→  const [editGender, setEditGender] = useState(false);
 18→  const [editPassword, setEditPassword] = useState(false);
 19→  const [editPlan, setEditPlan] = useState(false);
 20→
 21→  const activateEditField = (fieldName) => {
 22→    if (fieldName === "fullname") {
 23→      setEditFullName(true);
 24→      setEditEmail(false);
 25→      setEditGender(false);
 26→      setEditPassword(false);
 27→    }
 28→    if (fieldName === "email") {
 29→      setEditEmail(true);
 30→      setEditFullName(false);
 31→      setEditGender(false);
 32→      setEditPassword(false);
 33→    }
 34→    if (fieldName === "gender") {
 35→      setEditGender(true);
 36→      setEditFullName(false);
 37→      setEditEmail(false);
 38→      setEditPassword(false);
 39→    }
 40→    if (fieldName === "password") {
 41→      setEditPassword(true);
 42→      setEditFullName(false);
 43→      setEditEmail(false);
 44→      setEditGender(false);
 45→    }
 46→    if (fieldName === "plan") {
 47→      setEditPlan(true);
 48→      setEditPassword(false);
 49→      setEditFullName(false);
 50→      setEditEmail(false);
 51→      setEditGender(false);
 52→    }
 53→  };
 54→  const submitForm = async (e, validationTarget, fieldName) => {
 55→    e.preventDefault();
 56→    const validationErrors = validationTarget(formValue[fieldName]);
 57→    if (Object.keys(validationErrors).length > 0) {
 58→      setFormErrors(validationErrors);
 59→    } else {
 60→      const updated = await updateUser(user.id, {
 61→        [fieldName]: formValue[fieldName],
 62→      });
 63→      if (!updated.success) {
 64→        if (updated.reason === "email") {
 65→          setFormErrors({ email: "Email already exists" });
 66→        }
 67→      } else {
 68→        setFormValue({});
 69→        setFormErrors({});
 70→        handleCancel(fieldName);
 71→        if (fieldName !== "password") {
 72→          setEditPassword(false);
 73→        }
 74→      }
 75→    }
 76→  };
 77→
 78→  const handleCancel = (target) => {
 79→    if (target === "fullname") {
 80→      setEditFullName(false);
 81→    }
 82→    if (target === "email") {
 83→      setEditEmail(false);
 84→    }
 85→    if (target === "password") {
 86→      setEditPassword(false);
 87→    }
 88→    if (target === "gender") {
 89→      setEditGender(false);
 90→    }
 91→    if (target === "plan") {
 92→      setEditPlan(false);
 93→    }
 94→    setFormValue({});
 95→    setFormErrors({});
 96→  };
 97→
 98→  const handelChange = (e) => {
 99→    const { name, value } = e.target;
100→    if (name === "email") {
101→      setFormValue({ ...formValue, email: value.toLowerCase() });
102→    } else {
103→      setFormValue({ ...formValue, [name]: value });
104→    }
105→  };
106→
107→  const deleteAcc = () => {
108→    deleteUser(user.id);
109→    setLoggedIn(false);
110→    setTriggeredLogout(true);
111→    navigator("/");
112→    window.scrollTo(0, 0);
113→  };
114→
115→  const formValidator = (field) => (formValueObject) => {
116→    const emailRegex = /^\w+([.-]?\w+)*@\w+([.-]?\w+)*(\.\w{2,3})+$/;
117→    const errors = {};
118→
119→    if (!formValueObject && field !== "password") {
120→      errors[field] = `This field is required`;
121→    } else if (field === "fullname" && formValueObject.length < 3) {
122→      errors[field] = `Full name is too short`;
123→    } else if (field === "fullname" && formValueObject === user.fullname) {
124→      errors[field] = `Full name is the same`;
125→    } else if (field === "email" && !emailRegex.test(formValueObject)) {
126→      errors[field] = `Email is not valid`;
127→    } else if (field === "email" && formValueObject === user.email) {
128→      errors[field] = `Email is the same`;
129→    }
130→    if (field === "password") {
131→      if (Object.keys(formValue).length === 0) {
132→        errors.password = `Password fields are empty`;
133→      } else if (
134→        formValue["password"] === undefined ||
135→        formValue["password"].length === 0
136→      ) {
137→        errors.password = `Password field is empty`;
138→      } else if (
139→        formValue["repeatedPassword"] === undefined ||
140→        formValue["repeatedPassword"].length === 0
141→      ) {
142→        errors.repeatedPassword = `Please repeat the password`;
143→      } else if (formValue["password"] !== formValue["repeatedPassword"]) {
144→        errors.password = `Passwords should match`;
145→      } else if (formValue["password"] && formValue["password"].length < 8) {
146→        errors.password = `Password should be min. 8 characters`;
147→      } else if (
148→        formValue["repeatedPassword"] &&
149→        formValue["repeatedPassword"].length < 8
150→      ) {
151→        errors.repeatedPassword = `Password should be min. 8 characters`;
152→      } else if (formValue["password"] === user.password) {
153→        errors.password = `New password can't be the same as old`;
154→      }
155→    }
156→    return errors;
157→  };
158→
159→  const validateFullName = formValidator("fullname");
160→  const validateEmail = formValidator("email");
161→  const validatePassword = formValidator("password");
162→  const validateGender = formValidator("gender");
163→  const validatePlan = formValidator("plan");
164→
165→  return (
166→    <div className="overflow-hidden bg-gray-900 shadow p-10">
167→      <div className="px-4 sm:px-0">
168→        <h3 className="text-base font-semibold leading-7 text-white">
169→          Profile Information
170→        </h3>
171→        <p className="mt-1 max-w-2xl text-sm leading-6 text-gray-400">
172→          Personal details and application
173→        </p>
174→      </div>
175→      <div className="mt-6 border-t border-white/10">
176→        <dl className="divide-y divide-white/10">
177→          <div className="px-4 py-6 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-0">
178→            <dt className="text-sm font-medium leading-6 text-white">
179→              Full name
180→            </dt>
181→            {editFullName ? (
182→              <section className="flex flex-col gap-2">
183→                <form
184→                  onSubmit={(e) => submitForm(e, validateFullName, "fullname")}
185→                  className="flex flex-row gap-2">
186→                  <label htmlFor="fullname" className="sr-only">
187→                    Full name
188→                  </label>
189→                  <input
190→                    onChange={handelChange}
191→                    defaultValue={formValue["fullname"]}
192→                    className="appearance-none relative block w-50 px-3 py-1 border border-gray-300 placeholder-gray-500 text-white rounded focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 focus:z-10 sm:text-sm"
193→                    id="fullname"
194→                    name="fullname"
195→                    type="text"
196→                    placeholder={user.fullname}
197→                  />
198→                  <button
199→                    type="submit"
200→                    className="cursor-pointer group relative w-full flex justify-center items-center py-1 px-2 border border-transparent text-sm font-medium rounded-md text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500">
201→                    Save
202→                  </button>
203→                  <button
204→                    type="button"
205→                    onClick={() => handleCancel("fullname")}
206→                    className="cursor-pointer group relative w-full flex justify-center items-center py-1 px-2 border border-transparent text-sm font-medium rounded-md text-white bg-indigo-600 hover:bg-indigo-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500">
207→                    Cancel
208→                  </button>
209→                </form>
210→                <span className="text-red-400">{formErrors["fullname"]}</span>
211→              </section>
212→            ) : (
213→              <dd className="flex flex-row gap-2 mt-1 text-sm leading-6 text-gray-400 sm:col-span-2 sm:mt-0">
214→                {user.fullname}{" "}
215→                <svg
216→                  xmlns="http://www.w3.org/2000/svg"
217→                  fill="none"
218→                  viewBox="0 0 24 24"
219→                  strokeWidth={1.5}
220→                  stroke="currentColor"
221→                  onClick={() => activateEditField("fullname")}
222→                  className="w-4 h-auto text-white cursor-pointer">
223→                  <path
224→                    strokeLinecap="round"
225→                    strokeLinejoin="round"
226→                    d="m16.862 4.487 1.687-1.688a1.875 1.875 0 1 1 2.652 2.652L10.582 16.07a4.5 4.5 0 0 1-1.897 1.13L6 18l.8-2.685a4.5 4.5 0 0 1 1.13-1.897l8.932-8.931Zm0 0L19.5 7.125M18 14v4.75A2.25 2.25 0 0 1 15.75 21H5.25A2.25 2.25 0 0 1 3 18.75V8.25A2.25 2.25 0 0 1 5.25 6H10"
227→                  />
228→                </svg>
229→              </dd>
230→            )}
231→          </div>
232→          <div className="px-4 py-6 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-0">
233→            <dt className="text-sm font-medium leading-6 text-white">
234→              Email address
235→            </dt>
236→            {editEmail ? (
237→              <section className="flex flex-col gap-2">
238→                <form
239→                  onSubmit={(e) => submitForm(e, validateEmail, "email")}
240→                  className="flex flex-row gap-2">
241→                  <label htmlFor="email" className="sr-only">
242→                    Email
